// Sauvegarde
function saveProjects() {
    localStorage.setItem("projects", JSON.stringify(projects));
}

// Affichage
function displayProjects(list) {
    var container = document.getElementById("projectsContainer");

    if (!container) return; // sécurité

    container.innerHTML = "";

    list.forEach((p, index) => {
        container.innerHTML += `
        <div class="project-card">
            <img src="${p.img}" width="100%">
            <h3>${p.title}</h3>
            <p>${p.price}€</p>

            <div class="buttons">
                <a href="${p.link}" target="_blank">Voir dashboard</a>
                <button onclick="editProject(${index})">Modifier</button>
                <button onclick="deleteProject(${index})">Supprimer</button>
            </div>
        </div>
        `;
    });
}

// Ajouter
var addBtn = document.getElementById("addProjectBtn");

if (addBtn) {
    addBtn.addEventListener("click", function () {
        var title = document.getElementById("projectTitle").value;
        var link = document.getElementById("projectLink").value;
        var price = parseFloat(document.getElementById("projectPrice").value);
        var img = document.getElementById("projectImg").value || "https://via.placeholder.com/300";

        if (title && link && price) {
            projects.push({ title, link, price, img });
            saveProjects();
            displayProjects(projects);

            // reset champs
            document.getElementById("projectTitle").value = "";
            document.getElementById("projectLink").value = "";
            document.getElementById("projectPrice").value = "";
            document.getElementById("projectImg").value = "";
        } else {
            alert("Remplir tous les champs !");
        }
    });
}

// Modifier
function editProject(index) {
    var newTitle = prompt("Nouveau titre :", projects[index].title);
    var newLink = prompt("Nouveau lien :", projects[index].link);
    var newPrice = prompt("Nouveau prix :", projects[index].price);
    var newImg = prompt("Nouvelle image :", projects[index].img);

    if (newTitle && newLink && newPrice) {
        projects[index] = {
            title: newTitle,
            link: newLink,
            price: parseFloat(newPrice),
            img: newImg || "https://via.placeholder.com/300"
        };

        saveProjects();
        displayProjects(projects);
    }
}

// Supprimer
function deleteProject(index) {
    if (confirm("Supprimer ce projet ?")) {
        projects.splice(index, 1);
        saveProjects();
        displayProjects(projects);
    }
}

// Acheter
function buyProject(title, price) {
    alert("Achat : " + title + " - " + price + "€");
}

// Recherche
var searchInput = document.getElementById("searchInput");

if (searchInput) {
    searchInput.addEventListener("input", function () {
        var query = this.value.toLowerCase();

        var filtered = projects.filter(p =>
            p.title.toLowerCase().includes(query)
        );

        displayProjects(filtered);
    });
}

// Logout
function logout() {
    localStorage.removeItem("isLoggedIn");
    window.location.href = "powerbi.html";
}

// Chargement initial
window.onload = function () {
    displayProjects(projects);
};
